import express, { Request, Response } from 'express';
import { createConnection } from 'typeorm';
import { Product } from './entity/Product'; // Assuming you have a Product entity defined in this file

const app = express();
const port = 3000;

createConnection().then(connection => {
  const productRepository = connection.getRepository(Product);
  
  app.get('/products', async (req: Request, res: Response) => {
    try {
      let queryString = 'SELECT * FROM Product WHERE 1=1'; // Start with a base where clause
      
      if (req.query.name) {
        queryString += ` AND name LIKE '%${req.query.name}%'`; // Append the name filter
      }
  
      if (req.query.categoryId) {
        queryString += ` AND category_id = ${req.query.categoryId}`; // Append the category id filter
      }
      
      const products = await productRepository.query(queryString);
      res.json(products);
    } catch (error) {
      console.log('Error: ', error);
      res.status(500).send({ message: 'An error occurred while fetching the data.' });
    }
  });
  
  app.listen(port, () => {
    console.log(`Server is running on port ${port}`);
  });
}).catch(error => console.log('TypeORM connection error: ', error));